#include <iostream>
#include <string>
#include <iomanip>

int main() {
    BankAccount account(-50.0); // Test initial balance correction
    std::cout << "Initial balance: $" << std::fixed << std::setprecision(2) << account.getBalance() << std::endl;

    double amount = 100.0;
    if (account.deposit(amount)) {
        std::cout << "Deposited $" << std::fixed << std::setprecision(2) << amount << ". New balance: $" << account.getBalance() << std::endl;
    } else {
        std::cout << "Failed to deposit $" << std::fixed << std::setprecision(2) << amount << ". Current balance: $" << account.getBalance() << std::endl;
    }

    amount = 200.0;
    if (account.withdraw(amount)) {
        std::cout << "Withdrew $" << std::fixed << std::setprecision(2) << amount << ". New balance: $" << account.getBalance() << std::endl;
    } else {
        std::cout << "Failed to withdraw $" << std::fixed << std::setprecision(2) << amount << " due to insufficient funds. Current balance: $" << account.getBalance() << std::endl;
    }

    amount = 50.0;
    if (account.withdraw(amount)) {
        std::cout << "Withdrew $" << std::fixed << std::setprecision(2) << amount << ". New balance: $" << account.getBalance() << std::endl;
    } else {
        std::cout << "Failed to withdraw $" << std::fixed << std::setprecision(2) << amount << ". Current balance: $" << account.getBalance() << std::endl;
    }

    amount = -10.0;
    if (account.deposit(amount)) {
        std::cout << "Deposited $" << std::fixed << std::setprecision(2) << amount << ". New balance: $" << account.getBalance() << std::endl;
    } else {
        std::cout << "Failed to deposit negative amount. Current balance: $" << account.getBalance() << std::endl;
    }

    amount = -20.0;
    if (account.withdraw(amount)) {
        std::cout << "Withdrew $" << std::fixed << std::setprecision(2) << amount << ". New balance: $" << account.getBalance() << std::endl;
    } else {
        std::cout << "Failed to withdraw negative amount. Current balance: $" << account.getBalance() << std::endl;
    }

    std::cout << "Final balance: $" << std::fixed << std::setprecision(2) << account.getBalance() << std::endl;

    return 0;
}
